/* lowlevel_file.c */
#include "common.h"
#include "mballoc.h"
#include "util.h"
#include "lowlevel_file.h"
#include <string.h> // for memcpy and memset
#include <stdlib.h>
#include <unistd.h>
#include <stdbool.h>

void* access_data[10000000];
void* access_extent[10000000];
unsigned access_count = 0;

void dump_access_queue() {
    FILE* file = fopen("access.log", "w");
    if (!file) {
        perror("Failed to open file for dumping access queue");
        return;
    }
    
    fprintf(file, "Access Queue Entries: %u\n", access_count);
    for (unsigned i = 0; i < access_count; i++) {
        fprintf(file, "%p %p\n", access_extent[i], access_data[i]);
    }
    
    fclose(file);
}

static unsigned char* malloc_pages(unsigned pages) {
    if (pages == 0) return NULL;
    unsigned char* data = malloc(pages * PG_SIZE);
    if (data) memset(data, 0, pages * PG_SIZE);
    return data;
}

static bool is_allocated(struct inode *node, unsigned page) {
    Extent *curr = node->extents;
    while (curr) {
        if (page >= curr->start_page && 
            page < curr->start_page + curr->length) return true;
        curr = curr->next;
    }
    return false;
}

static void try_merge_extents(struct inode *node) {
    if (!node || !node->extents) return;
    
    bool merged;
    do {
        merged = false;
        
        for (Extent *current = node->extents; current; current = current->next) {
            Extent *prev = NULL;
            for (Extent *other = node->extents; other; ) {
                Extent *next = other->next;
                
                // Skip comparing the same extent
                if (other == current) {
                    prev = other;
                    other = next;
                    continue;
                }
                
                // Check if current's end connects with other's start
                if (current->data + current->length * PG_SIZE == other->data) {
                    // printf("Merging extents: %u and %u\n", current->start_page, other->start_page);
                    
                    // Merge extents
                    current->length += other->length;
                    
                    // Remove 'other' from the list
                    if (prev) {
                        prev->next = other->next;
                    } else {
                        node->extents = other->next;
                    }
                    free(other);
                    merged = true;
                    break; // Restart the scan since list changed
                }
                
                prev = other;
                other = next;
            }
            
            if (merged) break; // Restart the outer loop
        }
    } while (merged); // Continue until no more merges are possible
}

void file_allocate(struct inode *node, unsigned offset, unsigned len) {
    if (len == 0 || offset + len > MAX_FILE_SIZE) return;
    
    unsigned start_page = offset / PG_SIZE;
    unsigned end_page = (offset + len - 1) / PG_SIZE;
    end_page = end_page >= INDEXTB_NUM ? INDEXTB_NUM-1 : end_page;

    // Find maximal contiguous unallocated blocks
    unsigned current = start_page;
    while (current <= end_page) {
        if (is_allocated(node, current)) { current++; continue; }

        // Find block length
        unsigned block_start = current;
        while (current <= end_page && !is_allocated(node, current)) current++;
        unsigned block_length = current - block_start;

        mballoc(node, block_start, block_length);
    }
    
    // Try to merge adjacent extents after allocation
    try_merge_extents(node);
}

static Extent* find_extent(struct inode *node, unsigned page) {
    Extent *curr = node->extents;
    while (curr) {
        if (page >= curr->start_page && 
            page < curr->start_page + curr->length) return curr;
        curr = curr->next;
    }
    return NULL;
}

void file_read(struct inode *node, unsigned offset, unsigned len, char *data) {
    unsigned cur = offset, remaining = len;
    char *dest = data;

    while (remaining > 0) {
        unsigned page = cur / PG_SIZE;
        unsigned page_off = cur % PG_SIZE;
        unsigned copy_len = PG_SIZE - page_off;
        copy_len = copy_len > remaining ? remaining : copy_len;

        if (page >= INDEXTB_NUM) {
            memset(dest, 0, copy_len);  // Out of bounds
        } else {
            Extent *ext = find_extent(node, page);
            if (ext) {
                unsigned ext_offset = (page - ext->start_page) * PG_SIZE + page_off;
                memcpy(dest, ext->data + ext_offset, copy_len);
                access_data[access_count] = ext->data + ext_offset;
                access_extent[access_count] = ext;
                access_count++;
            } else {
                memset(dest, 0, copy_len);  // Unallocated page
            }
        }
        // usleep(1000);
        dest += copy_len;
        cur += copy_len;
        remaining -= copy_len;
    }
    if (access_count % 100 == 0) {
        dump_access_queue();
    }
}

void file_write(struct inode *node, unsigned offset, unsigned len, const char *data) {
    file_allocate(node, offset, len);  // Ensure allocation first

    unsigned cur = offset, remaining = len;
    const char *src = data;

    while (remaining > 0) {
        unsigned page = cur / PG_SIZE;
        unsigned page_off = cur % PG_SIZE;
        unsigned copy_len = PG_SIZE - page_off;
        copy_len = copy_len > remaining ? remaining : copy_len;

        if (page >= INDEXTB_NUM) break;  // Max file size

        Extent *ext = find_extent(node, page);
        if (ext) {
            unsigned ext_offset = (page - ext->start_page) * PG_SIZE + page_off;
            if (src) {
                memcpy(ext->data + ext_offset, src, copy_len);
                src += copy_len;
            } else {
                memset(ext->data + ext_offset, 0, copy_len);
            }
            access_data[access_count] = ext->data + ext_offset;
            access_extent[access_count] = ext;
            access_count++;
        }
        cur += copy_len;
        remaining -= copy_len;
    }
    if (access_count % 100 == 0) {
        dump_access_queue();
    }
}

void clear_file(struct inode *node, unsigned start, unsigned len) {
    file_write(node, start, len, NULL);  // NULL triggers zero-fill
}